#include <stdio.h>

int main(){
    int repaso,limite,paginas,inicio,aceleracion;
    int cant=0;
    scanf("%d %d %d %d %d",&paginas,&inicio,&limite,&aceleracion,&repaso);
    while(paginas>0){

        if(cant==0){
            paginas=paginas-inicio;

        }
        else{
            paginas=paginas-inicio+repaso;

        }
        if(limite > inicio+aceleracion)
            inicio=inicio+aceleracion;
        else
            inicio=limite;
        cant++;

    }
    printf("%d",cant);
    return 0;
}

