fn main() {
  scanln!(c: u32, v0: u32, v1: u32, a: u32, l: u32);
  let mut speed = v0;
  let mut pages = 0;
  let mut days = 0;
  loop {
    days += 1;
    pages += speed;
    if pages >= c { break; }
    speed = std::cmp::min(speed + a, v1);
    pages -= l;
  }
  println!("{}", days);
